36	char compare_single_items(int item_idx1, int item_idx2) {
37	    if (item_idx1 == item_idx2) return '=';
38	    std::pair<int, int> query_pair_key = {std::min(item_idx1, item_idx2), std::max(item_idx1, item_idx2)};
39	    auto it = comparison_results_cache_1v1.find(query_pair_key);
40	    if (it != comparison_results_cache_1v1.end()) {
41	        char cached_res = it->second;
42	        if (item_idx1 == query_pair_key.first) return cached_res;
43	        return (cached_res == '<' ? '>' : (cached_res == '>' ? '<' : '='));
44	    }
45	    if (queries_made >= Q_total_global) return '=';
46	    char res_direct = perform_query_actual({item_idx1}, {item_idx2});
47	    if (item_idx1 < item_idx2) {
48	        comparison_results_cache_1v1[query_pair_key] = res_direct;
49	    } else {
50	        char reversed_res = (res_direct == '<' ? '>' : (res_direct == '>' ? '<' : '='));
51	        comparison_results_cache_1v1[query_pair_key] = reversed_res;
52	    }
53	    return res_direct;
54	}
