76	void merge_for_sort(std::vector<int>& items_to_sort, int left, int mid, int right) {
77	    int n1 = mid - left + 1;
78	    int n2 = right - mid;
79	    std::vector<int> L_half(n1), R_half(n2);
80	    for (int i = 0; i < n1; i++) L_half[i] = items_to_sort[left + i];
81	    for (int j = 0; j < n2; j++) R_half[j] = items_to_sort[mid + 1 + j];
82	    int i = 0, j = 0, k = left;
83	    while (i < n1 && j < n2) {
84	        char cmp_res = compare_single_items(L_half[i], R_half[j]);
85	        if (cmp_res == '<' || cmp_res == '=') {
86	            items_to_sort[k++] = L_half[i++];
87	        } else {
88	            items_to_sort[k++] = R_half[j++];
89	        }
90	    }
91	    while (i < n1) items_to_sort[k++] = L_half[i++];
92	    while (j < n2) items_to_sort[k++] = R_half[j++];
93	}
