111	int calculate_estimated_query_cost(int N_val, int k_pivots_val) {
112	    if (k_pivots_val <= 0) return 0;
113	    if (k_pivots_val == 1) return (N_val > 1) ? (N_val - 1) : 0;
114	    double cost = 0;
115	    cost += static_cast<double>(k_pivots_val) * estimate_log2(static_cast<double>(k_pivots_val));
116	    for (int j = 2; j < k_pivots_val; ++j) {
117	        if (j - 1 > 0) cost += estimate_log2(static_cast<double>(j - 1));
118	    }
119	    cost += static_cast<double>(N_val - k_pivots_val) * estimate_log2(static_cast<double>(k_pivots_val));
120	    return static_cast<int>(std::ceil(cost));
121	}
