189	
190	        int p1_idx = sorted_pivot_item_indices[1];
191	        char res_p1_vs_p0 = compare_single_items(p1_idx, p0_idx);
192	        if (res_p1_vs_p0 == '=') {
193	            estimated_weights[p1_idx] = estimated_weights[p0_idx];
194	        } else if (res_p1_vs_p0 == '<') {
195	            estimated_weights[p1_idx] = std::max(1LL, estimated_weights[p0_idx] * FACTOR_LT_NUM / 100);
196	        } else {
197	            estimated_weights[p1_idx] = std::max(1LL, estimated_weights[p0_idx] * FACTOR_GT_NUM / 100);
