264	                    }
265	                }
266	                estimated_X_j = std::max(1LL, estimated_X_j);
267	                estimated_weights[current_pivot_idx] = estimated_weights[prev_pivot_idx] + estimated_X_j;
268	            }
269	            if (estimated_weights[current_pivot_idx] < estimated_weights[prev_pivot_idx]) {
270	                estimated_weights[current_pivot_idx] = estimated_weights[prev_pivot_idx];
271	            }
272	            if (res_curr_vs_prev == '>' && estimated_weights[current_pivot_idx] == estimated_weights[prev_pivot_idx]) {
273	                estimated_weights[current_pivot_idx] = estimated_weights[prev_pivot_idx] + 1;
274	            }
275	        }
276	
277	        // Estimate weights for non-pivot items
278	        for (int i = 0; i < N_items_global; ++i) {
279	            bool is_pivot_flag = false;
280	            for (int p_idx_val = 0; p_idx_val < k_pivots_chosen; ++p_idx_val) {
281	                if (sorted_pivot_item_indices[p_idx_val] == i) { is_pivot_flag = true; break; }
282	            }
283	            if (is_pivot_flag) continue;
284	
285	            int bs_low_arr_idx = 0, bs_high_arr_idx = k_pivots_chosen - 1;
286	            int found_pivot_idx_for_eq = -1;
287	
288	            while (bs_low_arr_idx <= bs_high_arr_idx) {
289	                if (queries_made >= Q_total_global && found_pivot_idx_for_eq == -1) break;
290	                int mid_p_arr_idx = bs_low_arr_idx + (bs_high_arr_idx - bs_low_arr_idx) / 2;
291	                char res_item_vs_p = compare_single_items(i, sorted_pivot_item_indices[mid_p_arr_idx]);
292	                if (res_item_vs_p == '=') { found_pivot_idx_for_eq = mid_p_arr_idx; break; }
293	                else if (res_item_vs_p == '<') { bs_high_arr_idx = mid_p_arr_idx - 1; }
294	                else { bs_low_arr_idx = mid_p_arr_idx + 1; }
295	            }
296	
297	            if (found_pivot_idx_for_eq != -1) {
298	                estimated_weights[i] = estimated_weights[sorted_pivot_item_indices[found_pivot_idx_for_eq]];
299	                continue;
300	            }
301	
302	            int insert_pos_arr_idx = bs_low_arr_idx;
303	            if (insert_pos_arr_idx == 0) {
304	                long long w_p0 = estimated_weights[sorted_pivot_item_indices[0]];
305	                if (k_pivots_chosen >= 2) {
306	                    long long w_p1 = estimated_weights[sorted_pivot_item_indices[1]];
307	                    if (w_p1 > w_p0 && w_p0 > 0 && w_p1 != 0) {
308	                        estimated_weights[i] = std::max(1LL, w_p0 * w_p0 / w_p1);
309	                    } else {
310	                        estimated_weights[i] = std::max(1LL, w_p0 * FACTOR_LT_NUM / 100);
311	                    }
312	                } else {
313	                    estimated_weights[i] = std::max(1LL, w_p0 * FACTOR_LT_NUM / 100);
314	                }
315	            } else if (insert_pos_arr_idx == k_pivots_chosen) {
316	                long long w_pk_1 = estimated_weights[sorted_pivot_item_indices[k_pivots_chosen - 1]];
317	                if (k_pivots_chosen >= 2) {
318	                    long long w_pk_2 = estimated_weights[sorted_pivot_item_indices[k_pivots_chosen - 2]];
319	                    if (w_pk_1 > w_pk_2 && w_pk_2 > 0) {
320	                        estimated_weights[i] = std::max(1LL, w_pk_1 * w_pk_1 / w_pk_2);
321	                    } else {
322	                        estimated_weights[i] = std::max(1LL, w_pk_1 * FACTOR_GT_NUM / 100);
323	                    }
324	                } else {
325	                    estimated_weights[i] = std::max(1LL, w_pk_1 * FACTOR_GT_NUM / 100);
326	                }
327	            } else {
