// Post-refinement greedy local search using estimated weights
// Try all possible swaps/moves between pairs of groups to reduce variance
{
    // Recompute current sum_sq
    double post_sum_sq = 0;
    for (long long s : group_sums_array) post_sum_sq += static_cast<double>(s) * s;

    bool improved = true;
    int ls_rounds = 0;
    while (improved && ls_rounds < 50) {
        improved = false;
        ls_rounds++;
        auto time_now = std::chrono::steady_clock::now();
        if (std::chrono::duration_cast<std::chrono::milliseconds>(time_now - program_start_time) >= time_limit_ms) break;

        for (int g1 = 0; g1 < D_groups_global && !improved; g1++) {
            for (int g2 = g1 + 1; g2 < D_groups_global && !improved; g2++) {
                // Try best swap between g1 and g2
                long long sum1 = group_sums_array[g1];
                long long sum2 = group_sums_array[g2];
                long long target_swap = (sum1 - sum2) / 2;

                int best_i1 = -1, best_i2 = -1;
                long long best_improvement = 0;

                for (int idx1 : group_items_indices[g1]) {
                    for (int idx2 : group_items_indices[g2]) {
                        long long w1 = estimated_weights[idx1];
                        long long w2 = estimated_weights[idx2];
                        long long new_s1 = sum1 - w1 + w2;
                        long long new_s2 = sum2 - w2 + w1;
                        double old_contrib = static_cast<double>(sum1)*sum1 + static_cast<double>(sum2)*sum2;
                        double new_contrib = static_cast<double>(new_s1)*new_s1 + static_cast<double>(new_s2)*new_s2;
                        double imp = old_contrib - new_contrib;
                        if (imp > best_improvement) {
                            best_improvement = imp;
                            best_i1 = idx1;
                            best_i2 = idx2;
                        }
                    }
                }

                if (best_i1 != -1 && best_improvement > 0) {
                    long long w1 = estimated_weights[best_i1];
                    long long w2 = estimated_weights[best_i2];
                    group_sums_array[g1] -= w1; group_sums_array[g1] += w2;
                    group_sums_array[g2] -= w2; group_sums_array[g2] += w1;
                    assignment_array[best_i1] = g2;
                    assignment_array[best_i2] = g1;

                    int pos1 = item_pos_in_group_vector[best_i1];
                    int back1 = group_items_indices[g1].back();
                    if (best_i1 != back1) { group_items_indices[g1][pos1] = back1; item_pos_in_group_vector[back1] = pos1; }
                    group_items_indices[g1].pop_back();

                    int pos2 = item_pos_in_group_vector[best_i2];
                    int back2 = group_items_indices[g2].back();
                    if (best_i2 != back2) { group_items_indices[g2][pos2] = back2; item_pos_in_group_vector[back2] = pos2; }
                    group_items_indices[g2].pop_back();

                    group_items_indices[g2].push_back(best_i1);
                    item_pos_in_group_vector[best_i1] = group_items_indices[g2].size() - 1;
                    group_items_indices[g1].push_back(best_i2);
                    item_pos_in_group_vector[best_i2] = group_items_indices[g1].size() - 1;

                    improved = true;
                }
            }
        }
    }
}

